mapper.select:
SELECT course_id, lecture_id, tenant_id, lecture_order, reg_dt, upd_dt
FROM tb_course_lecture
WHERE course_id = #{courseId}
AND tenant_id = #{tenantId}
ORDER BY lecture_order ASC, reg_dt DESC

